mapper.select:
SELECT , org.org_name AS org_name, parent.group_name AS parent_name, u.user_name AS create_by_name, (SELECT COUNT(1) FROM permission_group_authorized_objects pga WHERE pga.permission_group_id = pg.id) AS authorized_object_count FROM permission_groups pg LEFT JOIN po_organization org ON pg.org_id = org.org_id LEFT JOIN permission_groups parent ON pg.parent_id = parent.id LEFT JOIN po_users u ON pg.create_by = u.user_id
AND pg.group_name LIKE CONCAT('%', #{query.groupName}, '%')
AND pg.group_code LIKE CONCAT('%', #{query.groupCode}, '%')
AND u.user_name LIKE CONCAT('%', #{query.createByName}, '%')
AND pg.create_time >= #{query.createTimeStart}
AND pg.create_time <= #{query.createTimeEnd}
AND pg.status = #{query.status}
AND pg.org_id = #{query.orgId}
ORDER BY pg.create_time DESC

SELECT , org.org_name AS org_name, parent.group_name AS parent_name, u.user_name AS create_by_name FROM permission_groups pg LEFT JOIN po_organization org ON pg.org_id = org.org_id LEFT JOIN permission_groups parent ON pg.parent_id = parent.id LEFT JOIN po_users u ON pg.create_by = u.user_id
AND pg.group_name LIKE CONCAT('%', #{query.groupName}, '%')
AND pg.status = #{query.status}
AND pg.org_id = #{query.orgId}
ORDER BY pg.create_time DESC

SELECT COUNT(1)
FROM permission_groups
WHERE group_code = #{groupCode}

    AND id != #{excludeId}

SELECT COUNT(1)
FROM permission_groups
WHERE group_name = #{groupName}

    AND id != #{excludeId}
